    jQuery.tablesorter.addWidget( { id: 'vertical_group', priority:99, format: this.jquery_tablesort_vertical_group } ) ;

    console.info('[s-tab] . init sorting');

    jQuery( prefix ).tablesorter( {
        widgets : ['vertical_group'],
        sortRestart : true // Resets the sort direction so that clicking on an unsorted column will sort in the sortInitialOrder direction.
        } ) ;

    console.info('[s-tab] . add glyph icons to table header cells');

