cablechip.widgets.sortable_tables.prototype.jquery_tablesort_vertical_group = function (  table, config, widgetOptions, initFlag )
    {
    // -------------------------------------------------------------------------------------------------
    // loop thru the table,
    // - if the region name is the same as the line above, change the cells class name to blank it our
    //- table id must be sortable_table
    // ------------------------------------------------------------------------------------------------

    console.groupCollapsed( 'EVENT widget tablesorter : group rows vertically' );

    var rows        = table.tBodies[0].rows,
        header      = table.tHead.rows,
        is_sp_column = [],
        last_row    = [ 'xxx', 'xxx', 'xxx', 'xxx' ] ;

    console.info('[s-tab] . vertical cols widget' );
    console.info('[s-tab] . rows: ' + rows.length );

    if ( table.vertical_group_lock )
        {
        console.info('[s-tab] . STOP lock found' );
        }

    table.vertical_group_lock = true;

    for (var k = 0 ; k < 4; k++ )
        {
        if ( header[0].cells[ k ] && header[0].cells[ k ].className && header[0].cells[ k ].className.match( /sp-col/i )  )
            {
            is_sp_column[ k ] = true;
            }
        else
            {
            is_sp_column[ k ] = false ;
            }
        }

    for (var i = 0; i < rows.length; i++)
        {
        var always_show_cell = false ;

        for (var j = 0 ; j < 4; j++ )
            {
            if ( ! is_sp_column[ j ]  ) continue;

            if ( ! rows[ i ].cells[ j ] ) continue;         // check 1st 3 cols .. unless it doesnt have 3 cols

            //console.info('.. row: ' + i + ' = ' + region + ' from ' + rows[ i ].cells[ 0 ].className );

            var cell_data   = rows[ i ].cells[ j ].innerHTML,
                cell_class  = rows[ i ].cells[ j ].className ;

            if ( ! always_show_cell && cell_data == last_row[j] )
                {
                if ( cell_class != 'sp_col_hide' )  rows[ i ].cells[ j ].className  = 'sp_col_hide';
                }
            else
                {
                always_show_cell = true ; // show

                if ( cell_class != 'sp_col_show' )  rows[ i ].cells[ j ].className  = 'sp_col_show';
                }

            //console.info('..     = ' + rows[ i ].cells[ 0 ].className );

            last_row[j] = cell_data ;
            }
        }

    console.info( '[s-tab] . done' );

    table.vertical_group_lock = false;

    console.groupEnd();
    };

```

