Sorry, I can't run on other platform in my environment for some reasons.
Instead, I'll give you more detail.

At "const aiScene* Importer::ReadFile( const char* _pFile, unsigned int pFlags)" in Impoter.cpp,
the Importer check whether or not can read the file as extension in for loop.
In this point, assimp call "inline void AssetMetadata::Read(Document& doc)" in glTFAsset.inl in below sequence.

glTFImporter::CanRead
Asset::Load
AssetMetadata::Read

[Importer.cpp](https://github.com/assimp/assimp/blob/master/code/Importer.cpp)
```
const aiScene* Importer::ReadFile( const char* _pFile, unsigned int pFlags)
{
    ...
            if (!imp)   {
            // not so bad yet ... try format auto detection.
            const std::string::size_type s = pFile.find_last_of('.');
            if (s != std::string::npos) {
                DefaultLogger::get()->info("File extension not known, trying signature-based detection");
                for( unsigned int a = 0; a < pimpl->mImporter.size(); a++)  {

                    if( pimpl->mImporter[a]->CanRead( pFile, pimpl->mIOHandler, true)) {
                        imp = pimpl->mImporter[a];
                        break;
                    }
                }
            }
            // Put a proper error message if no suitable importer was found
            if( !imp)   {
                pimpl->mErrorString = "No suitable reader found for the file format of file \"" + pFile + "\".";
                DefaultLogger::get()->error(pimpl->mErrorString);
                return NULL;
            }
        }
    ...
}
```

[glTFImporter.cpp](https://github.com/assimp/assimp/blob/master/code/glTFImporter.cpp)

```
bool glTFImporter::CanRead(const std::string& pFile, IOSystem* pIOHandler, bool checkSig) const
{
    LOGE("gltf can read");
    const std::string &extension = GetExtension(pFile);

    if (extension != "gltf" && extension != "glb")
        return false;

    if (checkSig && pIOHandler) {
        glTF::Asset asset(pIOHandler);
        try {
            asset.Load(pFile, extension == "glb");
            std::string version = asset.asset.version;
            return !version.empty() && version[0] == '1';
        } catch (...) {
            return false;
        }
    }

    return false;
}
```

[glTFAsset.inl](https://github.com/assimp/assimp/blob/master/code/glTFAsset.inl)

```
inline void Asset::Load(const std::string& pFile, bool isBinary)
{
    ...
    // Load the metadata
    asset.Read(doc);
    ReadExtensionsUsed(doc);
    ...
}

inline void AssetMetadata::Read(Document& doc)
{
    // read the version, etc.
    if (Value* obj = FindObject(doc, "asset")) {
        ReadMember(*obj, "copyright", copyright);
        ReadMember(*obj, "generator", generator);

        premultipliedAlpha = MemberOrDefault(*obj, "premultipliedAlpha", false);

        if (Value* versionString = FindString(*obj, "version")) {
            version = versionString->GetString();
        } else if (Value* versionNumber = FindNumber (*obj, "version")) {
            char buf[4];

            ai_snprintf(buf, 4, "%.1f", versionNumber->GetDouble());

            version = buf;
        }

        if (Value* profile = FindObject(*obj, "profile")) {
            ReadMember(*profile, "api",     this->profile.api);
            ReadMember(*profile, "version", this->profile.version);
        }
    }

    if (version.empty() || version[0] != '1') {
        throw DeadlyImportError("GLTF: Unsupported glTF version: " + version);
    }
}
```

To allow readers to share articles on Facebook, Twitter, LinkedIn or just mail them, I simply added share buttons to my ``post_detail.html`` template just before ``</article>``. I myself typically only share individual thoughts on an article (gives more interactions) and do that manually.

For the share buttons I chose to use https://github.com/heiseonline/shariff which makes it easy to configure and just requires a simple ``<div>`` to be added (see documentation of shariff). I wrapped the shariff files in a simple template tag, so the ``<div>`` becomes ``{% shariff %}``:

    from django.conf import settings
    from django import template

    register = template.Library()

    @register.inclusion_tag('djangocms_blog/shariff.html', takes_context=True)
    def shariff(context, title=None, services=None, orientation=None):
        context['orientation'] = orientation if orientation else 'horizontal'
        context['services'] = escape(services if services else 
                                    settings.SHARIFF['services'])  # MUST be configured in settings.py
        if title:
            context['short_message'] = settings.SHARIFF.get('prefix', '') + title +\
                          settings.SHARIFF.get('postfix', '') 
        if 'mail-url' in settings.SHARIFF:
            context['mail_url'] = settings.SHARIFF['mail-url']
        return(context)

And in ``templates/djangocms_blog/shariff.html`` I have

    {% load static sekizai_tags %}
    {% addtoblock 'js' %}<script src="{% static 'js/shariff.min.js' %}"></script>{% endaddtoblock %} 
    {% addtoblock 'css' %}<link href="{% static 'css/shariff.min.css' %}" rel="stylesheet">{% endaddtoblock %}
    <div class="shariff" data-services="{{services}}" data-orientation="{{orientation}}"{% if mail_url %} data-mail-url="{{mail_url}}"{% endif %}{% if short_message %} data-title="{{short_message}}"{% endif %}></div>

