The point is to allow sass lint or style lint to cover bootstrap, as part of continuous integration.
Sass-lint now supports ignored files. Otherwise, here is partial gulp task to automatically clean bootstrap-variables.scss. See gulp-stylefmt Github site for details on its configuration.

const replace         = require('gulp-replace'),
    stylefmt        = require('gulp-stylefmt');

gulp.task('stylefmt', function () {
    return gulp.src('src/bootstrap-variables.scss')
        .pipe(replace('"', "'"))
        .pipe(replace(" 0", " "))
        .pipe(stylefmt())
        .pipe(gulp.dest('dest/'));
});
